module Kreuzberg
  # Bounding geometry for an OCR element.
  #
  # Supports both axis-aligned rectangles (from Tesseract) and 4-point quadrilaterals
  # (from PaddleOCR and rotated text detection).
  class OcrBoundingGeometry
    extend T::Sig
    extend T::Helpers

    sig { returns(T::Boolean) }
    def rectangle? = false

    sig { returns(T::Boolean) }
    def quadrilateral? = false
  end

  # Axis-aligned bounding box (typical for Tesseract output).
  class OcrBoundingGeometryRectangle < OcrBoundingGeometry
    extend T::Sig

    # Left x-coordinate in pixels
    sig { returns(Integer) }
    attr_reader :left

    # Top y-coordinate in pixels
    sig { returns(Integer) }
    attr_reader :top

    # Width in pixels
    sig { returns(Integer) }
    attr_reader :width

    # Height in pixels
    sig { returns(Integer) }
    attr_reader :height

    # @param left [Integer]
    # @param top [Integer]
    # @param width [Integer]
    # @param height [Integer]
    # @return [void]
    sig { params(left: Integer, top: Integer, width: Integer, height: Integer).void }
    def initialize(left:, top:, width:, height:)
      super()
      @left = left
      @top = top
      @width = width
      @height = height
    end

    # @return [Boolean] true when this variant is rectangle
