    # @param hash [Hash] a Hash deserialized from the native extension
    # @return [self]
    sig { params(hash: T::Hash[T.untyped, T.untyped]).returns(T.attached_class) }
    def self.from_hash(hash)
      new(left: hash[:left] || hash['left'], top: hash[:top] || hash['top'], width: hash[:width] || hash['width'],
          height: hash[:height] || hash['height'])
    end
  end

  # 4-point quadrilateral for rotated/skewed text (PaddleOCR).
  #
  # Points are in clockwise order starting from top-left:
  # `[top_left, top_right, bottom_right, bottom_left]`
  class OcrBoundingGeometryQuadrilateral < OcrBoundingGeometry
    extend T::Sig

    # Four corner points as `[(x, y), ...]` in clockwise order
    sig { returns(String) }
    attr_reader :points

    # @param points [String]
    # @return [void]
    sig { params(points: String).void }
    def initialize(points:)
      super()
